// Score Recommendation Decision — deterministic metrics
const testCase = $('Split In Batches').first().json;
const agentAOutput = $('Agent A Workload Analyst').first().json;
const agentBOutput = $('Agent B Career Matcher').first().json;
const fusionOutput = $('Fusion Judge').first().json;

// Extract arrays
const agentACodes = (agentAOutput.output && agentAOutput.output.recommended_courses_a) || [];
const agentBCodes = (agentBOutput.output && agentBOutput.output.recommended_courses_b) || [];
const fusionSchedule = (fusionOutput.output && fusionOutput.output.recommended_schedule) || {};
const fusionCourses = (fusionSchedule.courses || []).map(c => c.course_code);

// Helpers
function courseMap(courses) {
  const m = {};
  for (const c of courses) m[c.course_code] = c;
  return m;
}
function selectedCredits(codes, lookup) {
  return codes.reduce((sum, c) => sum + ((lookup[c] && lookup[c].credits) || 0), 0);
}
function poolPrecision(codes, flexLookup) {
  if (codes.length === 0) return 1;
  const valid = codes.filter(c => flexLookup[c]);
  return valid.length / codes.length;
}
function electiveCompliance(codes, flexLookup) {
  const groupsSeen = {};
  for (const c of codes) {
    const fc = flexLookup[c];
    if (fc && fc.elective_group) {
      if (groupsSeen[fc.elective_group]) return 0;
      groupsSeen[fc.elective_group] = true;
    }
  }
  return 1;
}
function computeNdcg(codes, relevanceGrades) {
  if (!relevanceGrades || Object.keys(relevanceGrades).length === 0) return null;
  const gains = codes.map(c => relevanceGrades[c] || 0);
  if (gains.length === 0) return null;
  let dcg = 0;
  for (let i = 0; i < gains.length; i++) dcg += gains[i] / Math.log2(i + 2);
  const ideal = Object.values(relevanceGrades).sort((a, b) => b - a).slice(0, codes.length);
  let idcg = 0;
  for (let i = 0; i < ideal.length; i++) idcg += ideal[i] / Math.log2(i + 2);
  return idcg === 0 ? 0 : dcg / idcg;
}
function workloadBalance(codes, slotsByCourse) {
  if (!slotsByCourse || codes.length === 0) return 1;
  const daySlots = {};
  const occupied = new Set();
  for (const c of codes) {
    const slots = slotsByCourse[c] || [];
    for (const s of slots) {
      const key = s.day + '-' + s.period;
      if (occupied.has(key)) return 0;
      occupied.add(key);
      daySlots[s.day] = (daySlots[s.day] || 0) + 1;
    }
  }
  const maxDay = Math.max(...Object.values(daySlots), 0);
  if (maxDay <= 2) return 1;
  if (maxDay === 3) return 0.5;
  return 0;
}
function prefPolicyCompliance(finalFlex, aCodes, bCodes, preferred) {
  const overlapA = finalFlex.filter(c => aCodes.includes(c)).length;
  const overlapB = finalFlex.filter(c => bCodes.includes(c)).length;
  if (preferred === 'A') return overlapA >= overlapB ? 1 : 0;
  return overlapB >= overlapA ? 1 : 0;
}
function safeAvg(vals) {
  const valid = vals.filter(v => v !== null && v !== undefined);
  if (valid.length === 0) return 0;
  return valid.reduce((a, b) => a + b, 0) / valid.length;
}

const flexLookup = courseMap(testCase.flexible_courses);
const mandatoryLookup = courseMap(testCase.mandatory_courses);
const expected = testCase.expected || {};
const slotsByCourse = testCase.slots_by_course || {};

// Preferred agent
let preferredAgent = expected.preferred_agent;
if (!preferredAgent) {
  if (testCase.cumulative_gpa < 2.5) preferredAgent = 'A';
  else if (testCase.career_goal && testCase.career_goal !== 'general') preferredAgent = 'B';
  else preferredAgent = 'A';
}

// --- Agent A Metrics ---
const a_schema_valid = Array.isArray(agentACodes) ? 1 : 0;
const a_pool_precision = poolPrecision(agentACodes, flexLookup);
const a_credit_compliance = selectedCredits(agentACodes, flexLookup) <= testCase.remaining_credit_budget ? 1 : 0;
const a_elective_compliance = electiveCompliance(agentACodes, flexLookup);
const a_empty_pool = (testCase.flexible_courses.length === 0) ? (agentACodes.length === 0 ? 1 : 0) : 1;
const a_workload = workloadBalance(agentACodes, slotsByCourse);
const a_hard_gate = a_schema_valid && a_pool_precision && a_credit_compliance && a_elective_compliance && a_empty_pool;
const a_score = safeAvg([a_pool_precision, a_credit_compliance, a_elective_compliance, a_empty_pool, a_workload]);

// --- Agent B Metrics ---
const b_schema_valid = Array.isArray(agentBCodes) ? 1 : 0;
const b_pool_precision = poolPrecision(agentBCodes, flexLookup);
const b_credit_compliance = selectedCredits(agentBCodes, flexLookup) <= testCase.remaining_credit_budget ? 1 : 0;
const b_elective_compliance = electiveCompliance(agentBCodes, flexLookup);
const b_empty_pool = (testCase.flexible_courses.length === 0) ? (agentBCodes.length === 0 ? 1 : 0) : 1;
const b_ndcg = computeNdcg(agentBCodes, expected.career_relevance);
const b_hard_gate = b_schema_valid && b_pool_precision && b_credit_compliance && b_elective_compliance && b_empty_pool;
const b_score = safeAvg([b_pool_precision, b_credit_compliance, b_elective_compliance, b_empty_pool, b_ndcg]);

// --- Fusion Metrics ---
const f_schema_valid = (fusionSchedule.total_credits !== undefined && Array.isArray(fusionSchedule.courses)) ? 1 : 0;
const mandatoryCodes = testCase.mandatory_courses.map(c => c.course_code);
const f_mandatory_recall = mandatoryCodes.length === 0 ? 1 : mandatoryCodes.filter(c => fusionCourses.includes(c)).length / mandatoryCodes.length;
const fusionFlexCodes = fusionCourses.filter(c => !mandatoryLookup[c]);
const f_pool_precision = fusionFlexCodes.length === 0 ? 1 : fusionFlexCodes.filter(c => flexLookup[c]).length / fusionFlexCodes.length;
const allCourseLookup = { ...flexLookup, ...mandatoryLookup };
const f_total_selected = selectedCredits(fusionCourses, allCourseLookup) + testCase.mandatory_credits;
const f_max_credit = (selectedCredits(fusionCourses, allCourseLookup) <= testCase.max_allowed_credits) ? 1 : 0;
const reportedTotal = fusionSchedule.total_credits || 0;
const actualTotal = fusionSchedule.courses ? fusionSchedule.courses.reduce((s, c) => s + (c.credits || 0), 0) : 0;
const f_total_correct = (reportedTotal === actualTotal) ? 1 : 0;
const f_elective = electiveCompliance(fusionFlexCodes, flexLookup);
const f_pref = prefPolicyCompliance(fusionFlexCodes, agentACodes, agentBCodes, preferredAgent);
const f_ndcg = computeNdcg(fusionCourses, expected.career_relevance);
const f_workload = workloadBalance(fusionCourses, slotsByCourse);
const f_hard_gate = f_schema_valid && (f_mandatory_recall >= 1) && f_pool_precision && f_max_credit && f_total_correct && f_elective;

// Fusion score with weighted formula
const coreAvg = safeAvg([f_mandatory_recall, f_pool_precision, f_max_credit, f_total_correct, f_elective].filter(v => v !== null));
let f_score = 0.45 * coreAvg + 0.25 * (f_pref !== null ? f_pref : 0) + 0.20 * (f_ndcg !== null ? f_ndcg : 0) + 0.10 * (f_workload !== null ? f_workload : 0);
if (f_ndcg === null) {
  const w = 0.45 + 0.25 + 0.10;
  f_score = (0.45 * coreAvg + 0.25 * f_pref + 0.10 * f_workload) / w;
}

const case_pass = !!(a_hard_gate && b_hard_gate && f_hard_gate && f_score >= 0.85);

return [{ json: {
  test_id: testCase.test_id,
  category: testCase.category,
  difficulty: testCase.difficulty,
  agent_a: { selected: agentACodes, hard_gate_pass: !!a_hard_gate, score: Math.round(a_score * 10000) / 10000, metrics: { schema_valid: a_schema_valid, pool_precision: a_pool_precision, credit_compliance: a_credit_compliance, elective_compliance: a_elective_compliance, empty_pool_compliance: a_empty_pool, workload_balance_score: a_workload } },
  agent_b: { selected: agentBCodes, hard_gate_pass: !!b_hard_gate, score: Math.round(b_score * 10000) / 10000, metrics: { schema_valid: b_schema_valid, pool_precision: b_pool_precision, credit_compliance: b_credit_compliance, elective_compliance: b_elective_compliance, empty_pool_compliance: b_empty_pool, career_ndcg: b_ndcg } },
  fusion: { selected: fusionCourses, hard_gate_pass: !!f_hard_gate, score: Math.round(f_score * 10000) / 10000, metrics: { schema_valid: f_schema_valid, mandatory_recall: f_mandatory_recall, pool_precision: f_pool_precision, max_credit_compliance: f_max_credit, total_credits_correct: f_total_correct, elective_compliance: f_elective, preference_policy_compliance: f_pref, career_ndcg: f_ndcg, workload_balance_score: f_workload } },
  case_pass: case_pass
} }];

// Merge deterministic result with explanation judge output
let result;
try {
  result = $('Score Recommendation Decision').first().json;
} catch(e) {
  result = { error: 'Could not read deterministic result' };
}

let explQuality = null;
let explNotes = 'Explanation judge unavailable';
try {
  const judgeOut = $input.first().json;
  const output = judgeOut.output || judgeOut;
  if (output.explanation_quality !== undefined && [0,1,2].includes(output.explanation_quality)) {
    explQuality = output.explanation_quality;
    explNotes = output.explanation_notes || '';
  }
} catch(e) {}

return [{ json: { ...result, explanation_quality: explQuality, explanation_notes: explNotes } }];

// Aggregate all collected results into final report
const staticData = $getWorkflowStaticData('global');
const results = staticData.results || [];

const total = results.length;
const passed = results.filter(r => r.case_pass).length;
const passRate = total > 0 ? Math.round((passed / total) * 10000) / 10000 : 0;

function avg(arr) {
  const valid = arr.filter(v => v !== null && v !== undefined);
  return valid.length > 0 ? Math.round((valid.reduce((a,b) => a+b, 0) / valid.length) * 10000) / 10000 : null;
}

const agentAPassRate = avg(results.map(r => r.agent_a && r.agent_a.hard_gate_pass ? 1 : 0));
const agentAAvgScore = avg(results.map(r => r.agent_a ? r.agent_a.score : null));
const agentBPassRate = avg(results.map(r => r.agent_b && r.agent_b.hard_gate_pass ? 1 : 0));
const agentBAvgScore = avg(results.map(r => r.agent_b ? r.agent_b.score : null));
const agentBNdcg = avg(results.map(r => r.agent_b && r.agent_b.metrics ? r.agent_b.metrics.career_ndcg : null));
const fusionPassRate = avg(results.map(r => r.fusion && r.fusion.hard_gate_pass ? 1 : 0));
const fusionAvgScore = avg(results.map(r => r.fusion ? r.fusion.score : null));
const fusionMandatory = avg(results.map(r => r.fusion && r.fusion.metrics ? r.fusion.metrics.mandatory_recall : null));
const fusionCredit = avg(results.map(r => r.fusion && r.fusion.metrics ? r.fusion.metrics.max_credit_compliance : null));
const fusionPref = avg(results.map(r => r.fusion && r.fusion.metrics ? r.fusion.metrics.preference_policy_compliance : null));
const explAvg = avg(results.map(r => r.explanation_quality));
const failedCases = results.filter(r => !r.case_pass).map(r => ({ test_id: r.test_id, category: r.category, agent_a_gate: r.agent_a ? r.agent_a.hard_gate_pass : false, agent_b_gate: r.agent_b ? r.agent_b.hard_gate_pass : false, fusion_gate: r.fusion ? r.fusion.hard_gate_pass : false, fusion_score: r.fusion ? r.fusion.score : 0 }));

// CSV output
const csvHeader = 'test_id,category,difficulty,case_pass,agent_a_score,agent_b_score,fusion_score,agent_a_hard_gate,agent_b_hard_gate,fusion_hard_gate,mandatory_recall,pool_precision,max_credit_compliance,total_credits_correct,elective_compliance,preference_policy_compliance,career_ndcg,workload_balance_score,explanation_quality';
const csvRows = results.map(r => {
  const fm = (r.fusion && r.fusion.metrics) || {};
